            // Copy data to the fixed-width buffer slot
            if (copy_len > 0) {
                memcpy(write_ptr, read_ptr, copy_len);
            }

            // Advance the write pointer by the fixed field capacity
            // (Padding is already handled by memset)
            write_ptr += field_capacity;

            // Advance the read pointer to the next token
            if (delimiter != NULL) {
                read_ptr = delimiter + 1; // Skip the comma
            } else {
                // If we reached the end of the input string, stay there.
                // Subsequent fields in this row (if any) will be empty (zero-filled).
                read_ptr += token_len;
            }
        }
    }

    // 7. Success
    *parsed_buffer = buffer;
    return 0;
}
